def compute_score():
    from pptx import Presentation
    required = ['obesity definition', 'global statistics', 'impact on health']
    prs = Presentation(modified_ppt_path)
    # Find Agenda slide by title
    # First try title placeholders:
    agenda_slide = None
    for slide in prs.slides:
        if slide.shapes.title and slide.shapes.title.text.strip().lower() == 'agenda':
            agenda_slide = slide
            break
    # If not found, check all shapes for text 'Agenda'
    if not agenda_slide:
        for slide in prs.slides:
            title_shapes = [sh for sh in slide.shapes if sh.has_text_frame and sh.text_frame.text.strip().lower() == 'agenda']
            if title_shapes:
                agenda_slide = slide
                break
    if not agenda_slide:
        return 'Agenda slide not found in modified presentation.', 0.0

    import re as _re
    _norm = lambda s: _re.sub(r"\s+", " ", (s or "")).strip().lower()
    required_n = [_norm(x) for x in required]
    found = []
    for shape in agenda_slide.shapes:
        if shape.has_text_frame and _norm(shape.text_frame.text) != "agenda":
            for para in shape.text_frame.paragraphs:
                text = _norm(para.text)
                if text:
                    found.append(text)
    missing = [item for item in required_n if item not in found]
    if not missing:
        return 'All required bullet points present on Agenda slide.', 1.0
    return f'Missing bullet points: {missing}', 0.0

def compute_score():
    from pptx import Presentation
    import os
    prs = Presentation(modified_ppt_path)
    agenda_slide = None
    # First try title placeholders:
    for slide in prs.slides:
        if slide.shapes.title and slide.shapes.title.text.strip().lower() == 'agenda':
            agenda_slide = slide
            break
    # If not found, check all shapes for text 'Agenda'
    if not agenda_slide:
        for slide in prs.slides:
            title_shapes = [sh for sh in slide.shapes if sh.has_text_frame and sh.text_frame.text.strip().lower() == 'agenda']
            if title_shapes:
                agenda_slide = slide
                break
    if not agenda_slide:
        return 'Agenda slide not found in modified presentation.', 0.0

    slide = agenda_slide  # slide_number is 1-based
    # Find all paragraphs in all shapes
    for shape in slide.shapes:
        # Skip title shape
        if shape == slide.shapes.title:
            continue
        bullet_texts = []

        if hasattr(shape, "text_frame") and shape.text_frame:
            for para in shape.text_frame.paragraphs:
                if para.level == 0 or para.level == 1:   # Accept both top-level and first indent
                    text = para.text.strip()
                    if text:
                        bullet_texts.append(text.lower())
        required_bullets = [
            "obesity definition",
            "global statistics",
            "impact on health"
        ]
        found = [any(rb == bt for bt in bullet_texts) for rb in required_bullets]
        if any(found) and not all(found):
            missing = [rb for rb, f in zip(required_bullets, found) if not f]
            return (f"Missing bullet points: {', '.join(missing)}.", 0.0)

        elif all(found):
            # Ensure no extra bullet points
            if len([x for x in bullet_texts if x.strip()]) != 3:
                return (f"Agenda slide has {len(bullet_texts)} bullet points instead of 3.", 0.0)
            else:
                return ("Agenda slide has exactly the required bullet points.", 1.0)
    return 'No bullet points found on Agenda slide.', 0.0

